  /**
   * ============================================
   * CENTRAL TOOL DASHBOARD
   * ============================================
   */

  /**
   * Dashboard-Daten abrufen
   */
  async getDashboardData() {
    try {
      const data = {
        metrics: this.metrics,
        recentOrders: await this.getRecentOrders(),
        topProducts: await this.getTopProducts(),
        campaignPerformance: await this.getCampaignPerformance(),
        seoHealth: await this.getSEOHealth(),
        inventoryStatus: await this.getInventoryStatus(),
        trends: await this.getCurrentTrends()
      };

      return data;
    } catch (error) {
      console.error('Error getting dashboard data:', error.message);
      throw error;
    }
  }

  /**
   * ============================================
   * HELPER FUNCTIONS
   * ============================================
   */

  async sendTelegramNotification(title, message) {
    try {
      await axios.post(
        `https://api.telegram.org/bot${this.config.telegram.botToken}/sendMessage`,
        {
          chat_id: this.config.telegram.chatId,
          text: `🚀 ${title}\n\n${message}`,
          parse_mode: 'HTML'
        }
      );
    } catch (error) {
      console.error('Error sending Telegram notification:', error.message);
    }
  }

  async getShopifyOrder(orderId) {
    const response = await axios.get(
      `${this.config.shopify.storeUrl}/admin/api/${this.config.shopify.apiVersion}/orders/${orderId}.json`,
      {
        headers: {
          'X-Shopify-Access-Token': this.config.shopify.accessToken
        }
      }
    );
    return response.data.order;
  }

  async getShopifyProduct(productId) {
    const response = await axios.get(
      `${this.config.shopify.storeUrl}/admin/api/${this.config.shopify.apiVersion}/products/${productId}.json`,
      {
        headers: {
          'X-Shopify-Access-Token': this.config.shopify.accessToken
        }
      }
    );
    return response.data.product;
  }

  async updateShopifyPrice(productId, newPrice) {
    await axios.put(
      `${this.config.shopify.storeUrl}/admin/api/${this.config.shopify.apiVersion}/products/${productId}.json`,
      {
        product: {
          id: productId,
          variants: [
            {
              price: newPrice
            }
          ]
        }
      },
      {
        headers: {
          'X-Shopify-Access-Token': this.config.shopify.accessToken,
          'Content-Type': 'application/json'
        }
      }
    );
  }

  async getRecentOrders() {
    const response = await axios.get(
      `${this.config.shopify.storeUrl}/admin/api/${this.config.shopify.apiVersion}/orders.json?status=any&limit=10`,
      {
        headers: {
          'X-Shopify-Access-Token': this.config.shopify.accessToken
        }
      }
    );
    return response.data.orders;
  }

  async getTopProducts() {
    const response = await axios.get(
      `${this.config.shopify.storeUrl}/admin/api/${this.config.shopify.apiVersion}/products.json?limit=10`,
      {
        headers: {
          'X-Shopify-Access-Token': this.config.shopify.accessToken
        }
      }
    );
    return response.data.products;
  }

  async getCurrentTrends() {
    return await this.analyzeMarketTrends('general e-commerce');
  }

